/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * Student: <Replace with your name and NetID>
 */ 

#include <assert.h>
#include <stdbool.h>

#include "csapp.h"

#define NTHREADS 8
#define SBUF_SIZE 64

typedef struct {
	int connfd;
	struct sockaddr_in clientaddr;
} conn_item_t;

typedef struct {
	conn_item_t *buf;
	int n;
	int front;
	int rear;
	int count;
	pthread_mutex_t mutex;
	pthread_cond_t slots;
	pthread_cond_t items;
} sbuf_t;

static void	client_error(int fd, const char *cause, int err_num, 
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);
static void	sbuf_init(sbuf_t *sp, int n);
static void	sbuf_deinit(sbuf_t *sp);
static void	sbuf_insert(sbuf_t *sp, conn_item_t item);
static conn_item_t sbuf_remove(sbuf_t *sp);
static void	*worker(void *arg);
static void	handle_transaction(int connfd, const struct sockaddr_in *clientaddr);
static int	append_line(char **bufp, size_t *lenp, size_t *capp, const char *line);
static void	normalize_header_line(const char *src, char *dst, size_t dstsz);
static int	connect_end_server(const char *hostname, const char *port);

static FILE *log_file = NULL;
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;
static sbuf_t sbuf;

/* 
 * Requires:
 *   <to be filled in by the student(s)> 
 *
 * Effects:
 *   <to be filled in by the student(s)> 
 */
int
main(int argc, char **argv)
{
	int listenfd;
	pthread_t tid;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	Signal(SIGPIPE, SIG_IGN);

	log_file = fopen("proxy.log", "w");
	if (log_file == NULL) {
		fprintf(stderr, "Failed to open proxy.log\n");
		exit(1);
	}

	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Failed to open listen socket on port %s\n", argv[1]);
		fclose(log_file);
		exit(1);
	}

	sbuf_init(&sbuf, SBUF_SIZE);
	for (int i = 0; i < NTHREADS; i++) {
		Pthread_create(&tid, NULL, worker, NULL);
		Pthread_detach(tid);
	}

	while (1) {
		conn_item_t item;
		socklen_t clientlen = sizeof(item.clientaddr);

		item.connfd = accept(listenfd, (SA *)&item.clientaddr, &clientlen);
		if (item.connfd < 0) {
			if (errno == EINTR)
				continue;
			continue;
		}
		sbuf_insert(&sbuf, item);
	}

	sbuf_deinit(&sbuf);
	fclose(log_file);

	/* Return success. */
	return (0);
}

static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Malloc(sizeof(conn_item_t) * n);
	sp->n = n;
	sp->front = 0;
	sp->rear = 0;
	sp->count = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->slots, NULL);
	pthread_cond_init(&sp->items, NULL);
}

static void
sbuf_deinit(sbuf_t *sp)
{
	Free(sp->buf);
	pthread_mutex_destroy(&sp->mutex);
	pthread_cond_destroy(&sp->slots);
	pthread_cond_destroy(&sp->items);
}

static void
sbuf_insert(sbuf_t *sp, conn_item_t item)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count == sp->n)
		pthread_cond_wait(&sp->slots, &sp->mutex);
	sp->buf[sp->rear] = item;
	sp->rear = (sp->rear + 1) % sp->n;
	sp->count++;
	pthread_cond_signal(&sp->items);
	pthread_mutex_unlock(&sp->mutex);
}

static conn_item_t
sbuf_remove(sbuf_t *sp)
{
	conn_item_t item;

	pthread_mutex_lock(&sp->mutex);
	while (sp->count == 0)
		pthread_cond_wait(&sp->items, &sp->mutex);
	item = sp->buf[sp->front];
	sp->front = (sp->front + 1) % sp->n;
	sp->count--;
	pthread_cond_signal(&sp->slots);
	pthread_mutex_unlock(&sp->mutex);
	return (item);
}

static void *
worker(void *arg)
{
	(void)arg;

	while (1) {
		conn_item_t item = sbuf_remove(&sbuf);
		handle_transaction(item.connfd, &item.clientaddr);
		close(item.connfd);
	}
	return (NULL);
}

static int
append_line(char **bufp, size_t *lenp, size_t *capp, const char *line)
{
	size_t line_len = strlen(line);
	size_t needed = *lenp + line_len + 1;
	if (needed > *capp) {
		size_t new_cap = *capp;
		while (new_cap < needed)
			new_cap *= 2;
		char *tmp = Realloc(*bufp, new_cap);
		if (tmp == NULL)
			return (-1);
		*bufp = tmp;
		*capp = new_cap;
	}
	memcpy(*bufp + *lenp, line, line_len);
	*lenp += line_len;
	(*bufp)[*lenp] = '\0';
	return (0);
}

static void
normalize_header_line(const char *src, char *dst, size_t dstsz)
{
	size_t len = strlen(src);

	while (len > 0 && (src[len - 1] == '\r' || src[len - 1] == '\n'))
		len--;
	if (len + 2 >= dstsz)
		len = dstsz - 3;
	memcpy(dst, src, len);
	dst[len] = '\r';
	dst[len + 1] = '\n';
	dst[len + 2] = '\0';
}

static int
connect_end_server(const char *hostname, const char *port)
{
	struct addrinfo hints, *listp, *p;
	int clientfd = -1;

	memset(&hints, 0, sizeof(struct addrinfo));
	hints.ai_socktype = SOCK_STREAM;
	hints.ai_flags = AI_NUMERICSERV;
	hints.ai_flags |= AI_ADDRCONFIG;

	if (getaddrinfo(hostname, port, &hints, &listp) != 0)
		return (-2);

	for (p = listp; p != NULL; p = p->ai_next) {
		clientfd = socket(p->ai_family, p->ai_socktype, p->ai_protocol);
		if (clientfd < 0)
			continue;
		if (connect(clientfd, p->ai_addr, p->ai_addrlen) != -1)
			break;
		close(clientfd);
		clientfd = -1;
	}

	freeaddrinfo(listp);
	return (clientfd);
}

static void
handle_transaction(int connfd, const struct sockaddr_in *clientaddr)
{
	rio_t client_rio, server_rio;
	char reqline[MAXLINE], method[16], uri[MAXLINE], version[32];
	char *hostname = NULL, *port = NULL, *pathname = NULL;
	int serverfd = -1, response_size = 0;
	bool response_started = false;

	rio_readinitb(&client_rio, connfd);

	ssize_t n = rio_readlineb(&client_rio, reqline, MAXLINE);
	if (n <= 0)
		return;

	if (n == MAXLINE - 1 && reqline[n - 1] != '\n') {
		client_error(connfd, "Request line too long", 400, "Bad Request",
		    "Proxy could not parse request");
		return;
	}

	if (sscanf(reqline, "%15s %8191s %31s", method, uri, version) != 3) {
		client_error(connfd, reqline, 400, "Bad Request",
		    "Proxy could not parse request");
		return;
	}

	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented",
		    "Proxy only implements GET");
		return;
	}

	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
		client_error(connfd, uri, 400, "Bad Request",
		    "Proxy requires an absolute http:// URI");
		goto out;
	}

	size_t req_cap = MAXBUF;
	size_t req_len = 0;
	char *server_req = Malloc(req_cap);
	server_req[0] = '\0';

	char line[MAXLINE], normalized_line[MAXLINE];
	char host_header[MAXLINE] = "";
	bool saw_host = false;
	if (append_line(&server_req, &req_len, &req_cap, "GET ") < 0 ||
	    append_line(&server_req, &req_len, &req_cap, pathname) < 0 ||
	    append_line(&server_req, &req_len, &req_cap, " HTTP/1.0\r\n") < 0) {
		Free(server_req);
		goto out;
	}

	while ((n = rio_readlineb(&client_rio, line, MAXLINE)) > 0) {
		if (!strcmp(line, "\r\n") || !strcmp(line, "\n"))
			break;

		if (n == MAXLINE - 1 && line[n - 1] != '\n') {
			client_error(connfd, "Header line too long", 400,
			    "Bad Request", "Proxy could not parse request headers");
			Free(server_req);
			goto out;
		}

		normalize_header_line(line, normalized_line, sizeof(normalized_line));

		if (!strncasecmp(line, "Host:", 5)) {
			saw_host = true;
			snprintf(host_header, sizeof(host_header), "%s", normalized_line);
		} else if (!strncasecmp(line, "Connection:", 11) ||
		    !strncasecmp(line, "Proxy-Connection:", 17) ||
		    !strncasecmp(line, "Keep-Alive:", 11)) {
			continue;
		} else if (append_line(&server_req, &req_len, &req_cap,
		    normalized_line) < 0) {
			Free(server_req);
			goto out;
		}
	}
